    fn call_named_host_function_with_this(
        &mut self,
        ctx: &GcContext<'gc>,
        name: &str,
        receiver: Option<&Value<'gc>>,
        args: &[Value<'gc>],
    ) -> Value<'gc> {
        if name == "Function.prototype.restrictedThrow" {
            self.throw_type_error(
                ctx,
                "'caller', 'callee', and 'arguments' properties may not be accessed on strict mode functions or the arguments objects for calls to them",
            );
            return Value::Undefined;
        }

        if name.starts_with("reflect.")
            || name.starts_with("array.")
            || name.starts_with("arrayBuffer.")
            || name.starts_with("atomics.")
            || name.starts_with("string.")
            || name.starts_with("object.")
            || name.starts_with("symbol.")
            || name.starts_with("error.")
            || name.starts_with("regexp.")
            || name.starts_with("promise.")
            || name.starts_with("boolean.")
            || name.starts_with("number.")
            || name.starts_with("bigint.")
            || name.starts_with("date.")
            || name.starts_with("global.")
            || name.starts_with("typedarray.")
            || name.starts_with("dataview.")
        {
            return self.call_host_fn(ctx, name, receiver, args);
        }

        match name {
            "iterator.self"
            | "iterator.next"
            | "object.getOwnPropertyDescriptors"
            | "object.getOwnPropertySymbols"
            | "object.__proto__.get"
            | "object.__proto__.set"
            | "object.toLocaleString"
            | "object.propertyIsEnumerable"
            | "object.valueOf"
            | "error.toString"
            | "object.isPrototypeOf" => self.call_host_fn(ctx, name, receiver, args),
            "symbol.toString" | "symbol.valueOf" => self.call_host_fn(ctx, name, receiver, args),
            _ => self.call_named_host_function(ctx, name, args),
        }
    }

    fn call_named_host_function(&mut self, ctx: &GcContext<'gc>, name: &str, args: &[Value<'gc>]) -> Value<'gc> {
        match name {
            "Function.prototype.restrictedThrow" => {
                self.throw_type_error(
                    ctx,
                    "'caller', 'callee', and 'arguments' properties may not be accessed on strict mode functions or the arguments objects for calls to them",
                );
                Value::Undefined
            }
            "__detachArrayBuffer__" => {
                let Some(Value::VmObject(buf_obj)) = args.first().cloned() else {
                    let mut err_map = IndexMap::new();
                    err_map.insert("__type__".to_string(), Value::from("TypeError"));
                    err_map.insert(
                        "message".to_string(),
                        Value::from("detachArrayBuffer requires an ArrayBuffer object"),
                    );
                    self.pending_throw = Some(Value::VmObject(new_gc_cell_ptr(ctx, err_map)));
                    return Value::Undefined;
                };

                let is_array_buffer = matches!(
                    buf_obj.borrow().get("__type__"),
                    Some(Value::String(s)) if crate::unicode::utf16_to_utf8(s) == "ArrayBuffer"
                );
                if !is_array_buffer {
                    let mut err_map = IndexMap::new();
                    err_map.insert("__type__".to_string(), Value::from("TypeError"));
                    err_map.insert(
                        "message".to_string(),
                        Value::from("detachArrayBuffer requires an ArrayBuffer object"),
                    );
                    self.pending_throw = Some(Value::VmObject(new_gc_cell_ptr(ctx, err_map)));
                    return Value::Undefined;
                }

                let bytes_arr = { buf_obj.borrow().get("__buffer_bytes__").cloned() };
                if let Some(Value::VmArray(bytes)) = bytes_arr {
                    bytes.borrow_mut(ctx).elements.clear();
                }

                let mut buf_borrow = buf_obj.borrow_mut(ctx);
                buf_borrow.insert("byteLength".to_string(), Value::Number(0.0));
                buf_borrow.insert("__detached__".to_string(), Value::Boolean(true));
                Value::Undefined
            }
            "console.log" => self.call_builtin(ctx, BUILTIN_CONSOLE_LOG, args),
            "console.warn" => self.call_builtin(ctx, BUILTIN_CONSOLE_WARN, args),
            "console.error" => self.call_builtin(ctx, BUILTIN_CONSOLE_ERROR, args),
            "AbstractModuleSource.prototype.@@toStringTag" => Value::Undefined,
            "os.getcwd" => {
                let cwd = std::env::current_dir()
                    .ok()
                    .map(|p| p.to_string_lossy().to_string())
                    .unwrap_or_default();
                Value::from(&cwd)
            }
            "os.getpid" => Value::Number(std::process::id() as f64),
            "os.getppid" => Value::Number(std::process::id() as f64),
            "os.open" => {
                let filename = args.first().map(value_to_string).unwrap_or_default();
                let flags = args.get(1).map(to_number).unwrap_or(0.0) as i32;

                let mut options = std::fs::OpenOptions::new();
                if flags & 2 != 0 {
                    options.read(true).write(true);
                } else if flags & 1 != 0 {
                    options.write(true);
                } else {
                    options.read(true);
                }
                if flags & 64 != 0 {
                    options.create(true);
                }
                if flags & 512 != 0 {
                    options.truncate(true);
                }

                match options.open(&filename) {
                    Ok(file) => {
                        let fd = vm_next_os_file_id();
                        VM_OS_FILE_STORE.lock().unwrap().insert(fd, file);
                        Value::Number(fd as f64)
                    }
                    Err(_) => Value::Number(-1.0),
                }
            }
            "os.close" => {
                let fd = args.first().map(to_number).unwrap_or(-1.0) as u64;
                if VM_OS_FILE_STORE.lock().unwrap().remove(&fd).is_some() {
                    Value::Number(0.0)
                } else {
                    Value::Number(-1.0)
                }
            }
            "os.write" => {
                let fd = args.first().map(to_number).unwrap_or(-1.0) as u64;
                let data = args.get(1).map(value_to_string).unwrap_or_default();
                let mut store = VM_OS_FILE_STORE.lock().unwrap();
                if let Some(file) = store.get_mut(&fd) {
                    match file.write(data.as_bytes()) {
                        Ok(n) => Value::Number(n as f64),
                        Err(_) => Value::Number(-1.0),
                    }
                } else {
                    Value::Number(-1.0)
                }
            }
            "os.read" => {
                let fd = args.first().map(to_number).unwrap_or(-1.0) as u64;
                let count = args.get(1).map(to_number).unwrap_or(0.0).max(0.0) as usize;
                let mut store = VM_OS_FILE_STORE.lock().unwrap();
                if let Some(file) = store.get_mut(&fd) {
                    let mut buf = vec![0u8; count];
                    match file.read(&mut buf) {
                        Ok(n) => {
                            buf.truncate(n);
                            Value::from(&*String::from_utf8_lossy(&buf))
                        }
                        Err(_) => Value::from(""),
                    }
                } else {
                    Value::from("")
                }
            }
            "os.seek" => {
                let fd = args.first().map(to_number).unwrap_or(-1.0) as u64;
                let offset = args.get(1).map(to_number).unwrap_or(0.0) as i64;
                let whence = args.get(2).map(to_number).unwrap_or(0.0) as i32;
                let mut store = VM_OS_FILE_STORE.lock().unwrap();
                if let Some(file) = store.get_mut(&fd) {
                    let seek_from = match whence {
                        0 => SeekFrom::Start(offset.max(0) as u64),
                        1 => SeekFrom::Current(offset),
                        2 => SeekFrom::End(offset),
                        _ => SeekFrom::Start(offset.max(0) as u64),
                    };
                    match file.seek(seek_from) {
                        Ok(pos) => Value::Number(pos as f64),
                        Err(_) => Value::Number(-1.0),
                    }
                } else {
                    Value::Number(-1.0)
                }
            }
            "os.path.basename" => {
                let p = args.first().map(value_to_string).unwrap_or_default();
                let base = std::path::Path::new(&p)
                    .file_name()
                    .map(|s| s.to_string_lossy().to_string())
                    .unwrap_or_default();
                Value::from(&base)
            }
            "os.path.dirname" => {
                let p = args.first().map(value_to_string).unwrap_or_default();
                let dir = std::path::Path::new(&p)
                    .parent()
                    .map(|s| s.to_string_lossy().to_string())
                    .unwrap_or_default();
                Value::from(&dir)
            }
            "os.path.join" => {
                let mut pb = std::path::PathBuf::new();
                for a in args {
                    pb.push(value_to_string(a));
                }
                Value::from(&*pb.to_string_lossy())
            }
            "os.path.extname" => {
                let p = args.first().map(value_to_string).unwrap_or_default();
                let ext = std::path::Path::new(&p)
                    .extension()
                    .map(|s| format!(".{}", s.to_string_lossy()))
                    .unwrap_or_default();
                Value::from(&ext)
            }
            _ => Value::Undefined,
        }
    }

    /// Get or create the property map for a VmFunction (keyed by IP).
    /// Auto-creates a `prototype` object with `constructor` back-reference on first access.
    fn get_fn_props(&mut self, ctx: &GcContext<'gc>, ip: usize, arity: u8) -> VmObjectHandle<'gc> {
        if let Some(existing) = self.fn_props.get(&ip) {
            return *existing;
        }
        let is_generator = self.chunk.generator_function_ips.contains(&ip);
        let is_async = self.chunk.async_function_ips.contains(&ip);
        let is_async_generator = is_async && is_generator;
        let is_method = self.chunk.method_function_ips.contains(&ip);
        let is_class_ctor = self.chunk.class_constructor_ips.contains(&ip);
        let is_arrow = self.chunk.arrow_function_ips.contains(&ip);
        let mut props = IndexMap::new();
        let needs_prototype = !is_arrow && (!is_async || is_async_generator) && (!is_method || is_generator);
        // __proto__ for the function itself
        if is_async_generator && !matches!(self.async_generator_function_prototype, Value::Undefined) {
            props.insert("__proto__".to_string(), self.async_generator_function_prototype.clone());
        } else if is_generator && !is_async && !matches!(self.generator_function_prototype, Value::Undefined) {
            props.insert("__proto__".to_string(), self.generator_function_prototype.clone());
        } else if is_async {
            if let Some(async_fn_proto) = self.globals.get("__async_function_prototype").cloned() {
                props.insert("__proto__".to_string(), async_fn_proto);
            } else if let Some(Value::VmObject(function_ctor)) = self.globals.get("Function")
                && let Some(fn_proto) = function_ctor.borrow().get("prototype").cloned()
            {
                props.insert("__proto__".to_string(), fn_proto);
            }
        } else if let Some(Value::VmObject(function_ctor)) = self.globals.get("Function")
            && let Some(fn_proto) = function_ctor.borrow().get("prototype").cloned()
        {
            props.insert("__proto__".to_string(), fn_proto);
        }
        // Insert length before name and prototype (spec order: length, name, prototype)
        let observable_length = self.chunk.fn_lengths.get(&ip).copied().unwrap_or(arity as usize) as f64;
        props.insert("length".to_string(), Value::Number(observable_length));
        props.insert("__readonly_length__".to_string(), Value::Boolean(true));
        props.insert("__nonenumerable_length__".to_string(), Value::Boolean(true));
        if is_method || is_generator {
            props.insert("__non_constructor__".to_string(), Value::Boolean(true));
        }
        // Set function name
        if let Some(name) = self.chunk.fn_names.get(&ip) {
            props.insert("name".to_string(), Value::from(name));
        } else {
            props.insert("name".to_string(), Value::String(Vec::new()));
        }
        props.insert("__readonly_name__".to_string(), Value::Boolean(true));
        props.insert("__nonenumerable_name__".to_string(), Value::Boolean(true));
        // prototype property (after length and name)
        if needs_prototype {
            let mut proto = IndexMap::new();
            proto.insert("constructor".to_string(), Value::VmFunction(ip, arity));
            proto.insert("__nonenumerable_constructor__".to_string(), Value::Boolean(true));
            // Generator functions: fn.prototype.__proto__ = %GeneratorPrototype%
            // Regular functions: fn.prototype.__proto__ = Object.prototype
            if is_generator {
                if is_async_generator && !matches!(self.async_generator_prototype, Value::Undefined) {
                    proto.insert("__proto__".to_string(), self.async_generator_prototype.clone());
                } else if !matches!(self.generator_prototype, Value::Undefined) {
                    proto.insert("__proto__".to_string(), self.generator_prototype.clone());
                }
            } else if let Some(Value::VmObject(obj_global)) = self.globals.get("Object")
                && let Some(obj_proto) = obj_global.borrow().get("prototype").cloned()
            {
                proto.insert("__proto__".to_string(), obj_proto);
            }
            props.insert("prototype".to_string(), Value::VmObject(new_gc_cell_ptr(ctx, proto)));
            props.insert("__nonenumerable_prototype__".to_string(), Value::Boolean(true));
            props.insert("__nonconfigurable_prototype__".to_string(), Value::Boolean(true));
            if is_class_ctor {
                props.insert("__readonly_prototype__".to_string(), Value::Boolean(true));
            }
        }
        let props_rc = new_gc_cell_ptr(ctx, props);
        self.fn_props.insert(ip, props_rc);
        props_rc
    }

    fn get_native_fn_props(&mut self, ctx: &GcContext<'gc>, id: u8) -> VmObjectHandle<'gc> {
        if let Some(existing) = self.native_fn_props.get(&id) {
            return *existing;
        }

        let mut props = IndexMap::new();
        props.insert("__native_id__".to_string(), Value::Number(id as f64));
        Self::insert_property_with_attributes(&mut props, "name", &Value::from(Self::native_function_name(id)), false, false, true);
        Self::insert_property_with_attributes(
            &mut props,
            "length",
            &Value::Number(Self::native_function_length(id)),
            false,
            false,
            true,
        );
        if let Some(Value::VmObject(function_ctor)) = self.globals.get("Function")
            && let Some(fn_proto) = function_ctor.borrow().get("prototype").cloned()
        {
            props.insert("__proto__".to_string(), fn_proto);
        }

        let props_rc = new_gc_cell_ptr(ctx, props);
        self.native_fn_props.insert(id, props_rc);
        props_rc
    }

    fn typeof_value(val: &Value<'gc>) -> &'static str {
        match val {
            Value::Number(_) => "number",
            Value::String(_) => "string",
            Value::Boolean(_) => "boolean",
            Value::Undefined => "undefined",
            Value::Null => "object",
            Value::Symbol(_) => "symbol",
            Value::VmFunction(..) | Value::VmClosure(..) | Value::Closure(..) | Value::Function(..) | Value::VmNativeFunction(_) => {
                "function"
            }
            Value::VmObject(map) => {
                let b = map.borrow();
                if b.contains_key("__vm_symbol__") {
                    "symbol"
                } else if b.contains_key("__fn_body__")
                    || b.contains_key("__native_id__")
                    || b.contains_key("__bound_target__")
                    || b.contains_key("__host_fn__")
                {
                    "function"
                } else {
                    "object"
                }
            }
            _ => "object",
        }
    }

    fn assign_named_property(
        &mut self,
        ctx: &GcContext<'gc>,
        obj: &Value<'gc>,
        key: &str,
        val: &Value<'gc>,
        receiver: Option<&Value<'gc>>,
    ) -> Result<Value<'gc>, JSError> {
        if let Some(result) = self.try_proxy_set(ctx, obj, key, val)? {
            return Ok(result);
        }

        let setter_receiver = receiver.cloned().unwrap_or_else(|| obj.clone());

        // Fast-path ordinary __proto__ assignment to direct prototype mutation.
        // If receiver already has an own '__proto__' property (data or accessor),
        // normal property semantics should take precedence.
        let has_own_dunder_proto = if key == "__proto__" {
            match &setter_receiver {
                Value::VmObject(map) => {
                    let b = map.borrow();
                    b.contains_key(OWN_DUNDER_PROTO_DATA_KEY)
                        || b.contains_key("__get___proto__")
                        || b.contains_key("__set___proto__")
                        || matches!(b.get("__proto__"), Some(Value::Property { .. }))
                }
                _ => false,
            }
        } else {
            false
        };

        if key == "__proto__" && !has_own_dunder_proto {
            let receiver_is_object_like = matches!(
                setter_receiver,
                Value::VmObject(_) | Value::VmArray(_) | Value::VmFunction(..) | Value::VmClosure(..) | Value::Object(_)
            );
            let receiver_is_proxy = matches!(&setter_receiver, Value::VmObject(map) if map.borrow().contains_key("__proxy_target__"));

            if receiver_is_object_like && !receiver_is_proxy && !Self::is_symbol_value(val) {
                if matches!(
                    val,
                    Value::Null | Value::VmObject(_) | Value::VmArray(_) | Value::VmFunction(..) | Value::VmClosure(..) | Value::Object(_)
                ) {
                    match self.set_object_like_prototype(ctx, &setter_receiver, val) {
                        Ok(true) => return Ok(val.clone()),
                        Ok(false) => {
                            let mut err_map = IndexMap::new();
                            err_map.insert("message".to_string(), Value::from("Cannot set prototype"));
                            err_map.insert("__type__".to_string(), Value::from("TypeError"));
                            err_map.insert("name".to_string(), Value::from("TypeError"));
                            let err = Value::VmObject(new_gc_cell_ptr(ctx, err_map));
                            self.handle_throw(ctx, &err)?;
                            return Ok(val.clone());
                        }
                        Err(err) => return Err(err),
                    }
                }
                // Object.prototype.__proto__ setter ignores primitive values.
                return Ok(val.clone());
            }
        }

        if let Value::VmFunction(ip, _) | Value::VmClosure(ip, _, _) = &val {
            // Record [[HomeObject]]-like information for functions assigned as methods.
            self.fn_home_objects.insert(*ip, obj.clone());
        }

        if let Value::VmObject(map) = &obj {
            let borrow = map.borrow();
            let is_frozen = matches!(borrow.get("__frozen__"), Some(Value::Boolean(true)));
            let is_non_ext = matches!(borrow.get("__non_extensible__"), Some(Value::Boolean(true)));
            let own_prop = if key == "__proto__" {
                borrow
                    .get(OWN_DUNDER_PROTO_DATA_KEY)
                    .cloned()
                    .or_else(|| match borrow.get("__proto__") {
                        Some(v @ Value::Property { .. }) => Some(v.clone()),
                        _ => None,
                    })
            } else {
                borrow.get(key).cloned()
            };
            let key_exists = if key == "__proto__" {
                borrow.contains_key(OWN_DUNDER_PROTO_DATA_KEY)
                    || matches!(borrow.get("__proto__"), Some(Value::Property { .. }))
                    || borrow.contains_key("__get___proto__")
                    || borrow.contains_key("__set___proto__")
            } else {
                borrow.contains_key(key) || borrow.contains_key(&format!("__get_{}", key)) || borrow.contains_key(&format!("__set_{}", key))
            };
            let readonly_key = format!("__readonly_{}__", key);
            let mut is_readonly = matches!(borrow.get(&readonly_key), Some(Value::Boolean(true)));
            // String wrappers have readonly character indices
            if !is_readonly
                && let Some(Value::String(type_str)) = borrow.get("__type__")
                && crate::unicode::utf16_to_utf8(type_str) == "String"
            {
                if key == "length" {
                    is_readonly = true;
                } else if let Some(Value::String(s)) = borrow.get("__value__")
                    && let Ok(idx) = key.parse::<usize>()
                    && idx < s.len()
                {
                    is_readonly = true;
                }
            }
            let getter_key = format!("__get_{}", key);
            let setter_key = format!("__set_{}", key);
            let mut proto_for_lookup = borrow.get("__proto__").cloned();
            if proto_for_lookup.is_none()
                && let Some(Value::String(type_name_u16)) = borrow.get("__type__")
            {
                let type_name = crate::unicode::utf16_to_utf8(type_name_u16);
                if let Some(Value::VmObject(ctor)) = self.globals.get(&type_name)
                    && let Some(type_proto) = ctor.borrow().get("prototype").cloned()
                {
                    proto_for_lookup = Some(type_proto);
                }
            }
            if proto_for_lookup.is_none()
                && let Some(Value::VmObject(object_ctor)) = self.globals.get("Object")
                && let Some(Value::VmObject(obj_proto)) = object_ctor.borrow().get("prototype").cloned()
                && !Gc::ptr_eq(*map, obj_proto)
            {
                proto_for_lookup = Some(Value::VmObject(obj_proto));
            }
            let proto_prop = proto_for_lookup
                .as_ref()
                .and_then(|proto| self.lookup_proto_chain(Some(proto), key));
            let own_prop_has_getter = matches!(own_prop.as_ref(), Some(Value::Property { getter: Some(_), .. }));
            let proto_prop_has_getter = matches!(proto_prop.as_ref(), Some(Value::Property { getter: Some(_), .. }));
            let own_prop_setter = match own_prop.as_ref() {
                Some(Value::Property { setter: Some(setter), .. }) if !matches!(&**setter, Value::Undefined) => Some((**setter).clone()),
                _ => None,
            };
            let proto_prop_setter = match proto_prop.as_ref() {
                Some(Value::Property { setter: Some(setter), .. }) if !matches!(&**setter, Value::Undefined) => Some((**setter).clone()),
                _ => None,
            };
            let has_getter = borrow.get(&getter_key).is_some()
                || own_prop_has_getter
                || proto_prop_has_getter
                || proto_for_lookup
                    .as_ref()
                    .and_then(|proto| self.lookup_proto_chain(Some(proto), &getter_key))
                    .is_some();
            let setter = own_prop_setter
                .or_else(|| borrow.get(&setter_key).cloned())
                .or(proto_prop_setter)
                .or_else(|| {
                    proto_for_lookup
                        .as_ref()
                        .and_then(|proto| self.lookup_proto_chain(Some(proto), &setter_key))
                });
            let proto_readonly = if !is_readonly && !key_exists {
                if let Some(proto) = proto_for_lookup.as_ref() {
                    self.lookup_proto_chain(Some(proto), &readonly_key).is_some()
                } else {
                    false
                }
            } else {
                false
            };
            drop(borrow);
            let getter_only = has_getter && setter.is_none();
            let non_ext_proto_mutation = is_non_ext && key == "__proto__" && !key_exists;

            if let Some(setter_fn) = setter {
                if self.is_value_callable(&setter_fn) {
                    let saved = std::mem::take(&mut self.try_stack);
                    let out = self.vm_call_function_value(ctx, &setter_fn, &setter_receiver, std::slice::from_ref(val));
                    self.try_stack = saved;
                    if let Err(err) = out {
                        self.set_pending_throw_from_error(&err);
                    }
                }
            } else if is_frozen || (is_non_ext && !key_exists) || non_ext_proto_mutation || is_readonly || proto_readonly || getter_only {
                let msg = if is_frozen {
                    format!("Cannot assign to read only property '{}' of object", key)
                } else if non_ext_proto_mutation {
                    "Cannot set prototype of a non-extensible object".to_string()
                } else if getter_only {
                    format!("Cannot set property {} of object which has only a getter", key)
                } else {
                    format!("Cannot add property {}, object is not extensible", key)
                };
                let err = self.make_type_error_object(ctx, &msg);
                self.handle_throw(ctx, &err)?;
            } else {
                let mut b = map.borrow_mut(ctx);
                if let Some(base_key) = key.strip_prefix("__get_").or_else(|| key.strip_prefix("__set_")) {
                    let real_base = if base_key == "__proto__" {
                        OWN_DUNDER_PROTO_DATA_KEY
                    } else {
                        base_key
                    };
                    if let Some(idx) = b.get_index_of(real_base) {
                        b.shift_remove(real_base);
                        b.shift_insert(idx, key.to_string(), val.clone());
                    } else {
                        b.insert(key.to_string(), val.clone());
                    }
                } else if key == "__proto__" {
                    b.insert(OWN_DUNDER_PROTO_DATA_KEY.to_string(), val.clone());
                } else {
                    b.insert(key.to_string(), val.clone());
                }
                if Gc::ptr_eq(*map, self.global_this) {
                    self.globals.insert(key.to_string(), val.clone());
                }
            }

            Ok(val.clone())
        } else if let Value::VmArray(arr) = &obj {
            if key == "length" {
                let borrow = arr.borrow();
                let readonly_length = matches!(borrow.props.get("__readonly_length__"), Some(Value::Boolean(true)));
                let frozen = matches!(borrow.props.get("__frozen__"), Some(Value::Boolean(true)));
                drop(borrow);
                if readonly_length || frozen {
                    let err = self.make_type_error_object(ctx, "Cannot assign to read only property 'length' of array");
                    self.handle_throw(ctx, &err)?;
                    return Ok(val.clone());
                }
                let mut desc = IndexMap::new();
                desc.insert("value".to_string(), val.clone());
                if !self.apply_array_property_descriptor(ctx, arr, "length", &desc) {
                    if let Some(thrown) = self.pending_throw.take() {
                        self.handle_throw(ctx, &thrown)?;
                    }
                    return Ok(val.clone());
                }
                return Ok(val.clone());
            }

            if let Ok(idx) = key.parse::<usize>() {
                // Only treat as array element index if idx < 2^32 - 1 (max array index per spec).
                // Keys >= 2^32 - 1 (e.g. "4294967295") are stored as string properties.
                if idx < 0xFFFF_FFFF {
                    let (has_getter, setter, is_readonly, key_exists, is_non_ext) = {
                        let borrow = arr.borrow();
                        let getter_key = format!("__get_{}", key);
                        let setter_key = format!("__set_{}", key);
                        let readonly_key = format!("__readonly_{}__", key);
                        let has_getter = borrow.props.get(&getter_key).is_some()
                            || borrow
                                .props
                                .get("__proto__")
                                .cloned()
                                .and_then(|proto| self.lookup_proto_chain(Some(&proto), &getter_key))
                                .is_some();
                        let setter = borrow.props.get(&setter_key).cloned().or_else(|| {
                            borrow
                                .props
                                .get("__proto__")
                                .cloned()
                                .and_then(|proto| self.lookup_proto_chain(Some(&proto), &setter_key))
                        });
                        let key_exists = (idx < borrow.elements.len() && !borrow.props.contains_key(&format!("__deleted_{}", idx)))
                            || borrow.props.contains_key(key)
                            || borrow.props.contains_key(&getter_key)
                            || borrow.props.contains_key(&setter_key);
                        let is_readonly = matches!(borrow.props.get(&readonly_key), Some(Value::Boolean(true)));
                        let is_non_ext = matches!(borrow.props.get("__non_extensible__"), Some(Value::Boolean(true)));
                        (has_getter, setter, is_readonly, key_exists, is_non_ext)
                    };

                    if let Some(setter_fn) = setter {
                        if self.is_value_callable(&setter_fn) {
                            match self.vm_call_function_value(ctx, &setter_fn, &setter_receiver, std::slice::from_ref(val)) {
                                Ok(_) => return Ok(val.clone()),
                                Err(err) => {
                                    self.set_pending_throw_from_error(&err);
                                    return Ok(val.clone());
                                }
                            }
                        }
                    } else if has_getter {
                        let err =
                            self.make_type_error_object(ctx, &format!("Cannot set property {} of object which has only a getter", key));
                        self.handle_throw(ctx, &err)?;
                        return Ok(val.clone());
                    } else if is_readonly || (is_non_ext && !key_exists) {
                        let msg = if is_non_ext && !key_exists {
                            format!("Cannot add property {}, object is not extensible", key)
                        } else {
                            format!("Cannot assign to read only property '{}'", key)
                        };
                        let err = self.make_type_error_object(ctx, &msg);
                        self.handle_throw(ctx, &err)?;
                        return Ok(val.clone());
                    }

                    let mut a = arr.borrow_mut(ctx);
                    if idx <= a.elements.len() + 1024 && idx < 1_000_000 {
                        while a.elements.len() <= idx {
                            let hole_idx = a.elements.len();
                            a.elements.push(Value::Undefined);
                            a.props.insert(format!("__deleted_{}", hole_idx), Value::Boolean(true));
                        }
                        a.elements[idx] = val.clone();
                        a.props.shift_remove(&format!("__deleted_{}", idx));
                    } else {
                        a.props.insert(key.to_string(), val.clone());
                    }
                    let old_len = if let Some(Value::Number(n)) = a.props.get("__array_length__") {
                        *n as u64
                    } else {
                        a.elements.len() as u64
                    };
                    let new_len = (idx as u64).saturating_add(1);
                    if new_len > old_len {
                        a.props.insert("__array_length__".to_string(), Value::Number(new_len as f64));
                    }
                    return Ok(val.clone());
                } else {
                    arr.borrow_mut(ctx).props.insert(key.to_string(), val.clone());
                    return Ok(val.clone());
                }
            }

            // Respect accessor/readonly/non-extensible behavior for non-index keys.
            let (is_non_ext, key_exists, is_readonly, has_getter, setter) = {
                let borrow = arr.borrow();
                let getter_key = format!("__get_{}", key);
                let setter_key = format!("__set_{}", key);
                let readonly_key = format!("__readonly_{}__", key);
                let is_non_ext = matches!(borrow.props.get("__non_extensible__"), Some(Value::Boolean(true)));
                let key_exists =
                    borrow.props.contains_key(key) || borrow.props.contains_key(&getter_key) || borrow.props.contains_key(&setter_key);
                let is_readonly = matches!(borrow.props.get(&readonly_key), Some(Value::Boolean(true)));
                let has_getter = borrow.props.get(&getter_key).is_some()
                    || borrow
                        .props
                        .get("__proto__")
                        .cloned()
                        .and_then(|proto| self.lookup_proto_chain(Some(&proto), &getter_key))
                        .is_some();
                let setter = borrow.props.get(&setter_key).cloned().or_else(|| {
                    borrow
                        .props
                        .get("__proto__")
                        .cloned()
                        .and_then(|proto| self.lookup_proto_chain(Some(&proto), &setter_key))
                });
                (is_non_ext, key_exists, is_readonly, has_getter, setter)
            };

            if let Some(setter_fn) = setter {
                if self.is_value_callable(&setter_fn) {
                    match self.vm_call_function_value(ctx, &setter_fn, obj, std::slice::from_ref(val)) {
                        Ok(_) => return Ok(val.clone()),
                        Err(err) => {
                            self.set_pending_throw_from_error(&err);
                            return Ok(val.clone());
                        }
                    }
                }
            } else {
                let getter_only = has_getter;
                if (is_non_ext && !key_exists) || is_readonly || getter_only {
                    let msg = if getter_only {
                        format!("Cannot set property {} of object which has only a getter", key)
                    } else {
                        format!("Cannot add property {}, object is not extensible", key)
                    };
                    let err = self.make_type_error_object(ctx, &msg);
                    self.handle_throw(ctx, &err)?;
                    return Ok(val.clone());
                }
            }

            arr.borrow_mut(ctx).props.insert(key.to_string(), val.clone());
            Ok(val.clone())
        } else if let Value::VmFunction(ip, arity) | Value::VmClosure(ip, arity, _) = &obj {
            // 'caller' and 'arguments' are restricted on all functions via %ThrowTypeError%
            if key == "caller" || key == "arguments" {
                let props = self.get_fn_props(ctx, *ip, *arity);
                let b = props.borrow();
                let has_own = b.contains_key(key) || b.contains_key(&format!("__get_{}", key)) || b.contains_key(&format!("__set_{}", key));
                drop(b);
                if !has_own {
                    let err = self.make_type_error_object(
                        ctx,
                        &format!(
                            "'{}' and 'arguments' are restricted function properties and cannot be accessed in this context",
                            key
                        ),
                    );
                    self.handle_throw(ctx, &err)?;
                    return Ok(val.clone());
                }
            }
            let props = self.get_fn_props(ctx, *ip, *arity);
            self.assign_named_property(ctx, &Value::VmObject(props), key, val, None)
        } else if let Value::Object(obj_ref) = &obj {
            crate::core::object_set_key_value(ctx, obj_ref, key, val)?;
            Ok(val.clone())
        } else {
            log::warn!("SetProperty on non-object: {}", value_to_string(obj));
            Ok(val.clone())
        }
    }

    fn resolve_super_base(&mut self, ctx: &GcContext<'gc>, receiver: &Value<'gc>) -> Option<Value<'gc>> {
        let active_func_ips: Vec<usize> = self.frames.iter().rev().map(|f| f.func_ip).collect();
        for func_ip in active_func_ips {
            if let Some(home_obj) = self.fn_home_objects.get(&func_ip).cloned() {
                match home_obj {
                    Value::VmObject(map) => {
                        let base = map.borrow().get("__proto__").cloned().unwrap_or(Value::Null);
                        match base {
                            Value::Null | Value::Undefined => {}
                            proto => return Some(proto),
                        }
                    }
                    Value::VmFunction(ip, arity) | Value::VmClosure(ip, arity, _) => {
                        let props = self.get_fn_props(ctx, ip, arity);
                        let base = props.borrow().get("__proto__").cloned().unwrap_or(Value::Null);
                        match base {
                            Value::Null | Value::Undefined => {}
                            proto => return Some(proto),
                        }
                    }
                    _ => {}
                }
            }
        }

        match receiver {
            Value::VmFunction(ip, arity) | Value::VmClosure(ip, arity, _) => {
                let props = self.get_fn_props(ctx, *ip, *arity);
                match props.borrow().get("__proto__").cloned().unwrap_or(Value::Null) {
                    Value::Null | Value::Undefined => None,
                    proto => Some(proto),
                }
            }
            Value::VmObject(map) => {
                let borrow = map.borrow();
                let has_own_proto = borrow.contains_key("__proto__");
                let immediate_proto = borrow.get("__proto__").cloned().unwrap_or(Value::Null);
                drop(borrow);

                match immediate_proto {
                    Value::VmObject(proto_obj) => match Value::VmObject(proto_obj) {
                        Value::Null | Value::Undefined => None,
                        proto => Some(proto),
                    },
                    Value::Null | Value::Undefined if !has_own_proto => {
                        if let Some(Value::VmObject(obj_global)) = self.globals.get("Object") {
                            obj_global.borrow().get("prototype").cloned()
                        } else {
                            None
                        }
                    }
                    _ => None,
                }
            }
            _ => None,
        }
    }

    fn infer_name_from_property_key(key: &str) -> String {
        if let Some(sym_desc) = key.strip_prefix("Symbol(").and_then(|s| s.strip_suffix(')')) {
            if sym_desc.is_empty() {
                String::new()
            } else {
                format!("[{}]", sym_desc)
            }
        } else if let Some(sym_desc) = key.strip_prefix("{ description: ").and_then(|s| s.strip_suffix(" }")) {
            if sym_desc == "undefined" || sym_desc.is_empty() {
                String::new()
            } else {
                format!("[{}]", sym_desc)
            }
        } else if key.starts_with("@@sym:") {
            // Handled by maybe_infer_function_name_from_key with symbol_values lookup
            String::new()
        } else {
            key.to_string()
        }
    }

    fn maybe_infer_function_name_from_key(&mut self, ctx: &GcContext<'gc>, key: &str, key_value: Option<&Value<'gc>>, val: &Value<'gc>) {
        let ip = match val {
            Value::VmFunction(ip, _) | Value::VmClosure(ip, _, _) => *ip,
            _ => return,
        };

        let inferred = if let Some(symbol_name) = key_value.and_then(|raw| match raw {
            Value::VmObject(sym_obj) if sym_obj.borrow().contains_key("__vm_symbol__") => {
                let desc_val = sym_obj.borrow().get("description").cloned().unwrap_or(Value::Undefined);
                Some(match desc_val {
                    Value::String(desc) => {
                        let desc = crate::unicode::utf16_to_utf8(&desc);
                        if desc.is_empty() { String::new() } else { format!("[{}]", desc) }
                    }
                    _ => String::new(),
                })
            }
            Value::Symbol(sym) => Some(match sym.description() {
                Some(desc) if !desc.is_empty() => format!("[{}]", desc),
                _ => String::new(),
            }),
            _ => None,
        }) {
            symbol_name
        } else if let Some(id_str) = key.strip_prefix("@@sym:") {
            if let Ok(id) = id_str.parse::<u64>() {
                if let Some(Value::VmObject(sym_obj)) = self.get_symbol_value(ctx, id) {
                    match sym_obj.borrow().get("description").cloned().unwrap_or(Value::Undefined) {
                        Value::String(desc) => {
                            let desc = crate::unicode::utf16_to_utf8(&desc);
                            if desc.is_empty() { String::new() } else { format!("[{}]", desc) }
                        }
                        _ => String::new(),
                    }
                } else {
                    String::new()
                }
            } else {
                String::new()
            }
        } else {
            Self::infer_name_from_property_key(key)
        };
        match self.chunk.fn_names.get(&ip) {
            Some(existing) if !existing.is_empty() => {}
            _ => {
                self.chunk.fn_names.insert(ip, inferred);
            }
        }

        // Function props are lazily cached but may already be materialized before
        // runtime name inference (e.g. MakeClosure paths). Keep the observable
        // `name` descriptor in sync when it is still anonymous.
        if let Some(props) = self.fn_props.get(&ip).copied() {
            let should_update = {
                let borrow = props.borrow();
                match borrow.get("name") {
                    Some(Value::String(s)) => s.is_empty(),
                    Some(_) => false,
                    None => true,
                }
            };
            if should_update {
                let new_name = self.chunk.fn_names.get(&ip).cloned().unwrap_or_default();
                let mut borrow = props.borrow_mut(ctx);
                borrow.insert("name".to_string(), Value::from(&new_name));
                borrow.insert("__readonly_name__".to_string(), Value::Boolean(true));
                borrow.insert("__nonenumerable_name__".to_string(), Value::Boolean(true));
            }
        }
    }

    fn maybe_infer_accessor_function_name_from_key(
        &mut self,
        ctx: &GcContext<'gc>,
        prefix: &str,
        key: &str,
        key_value: Option<&Value<'gc>>,
        val: &Value<'gc>,
    ) {
        let ip = match val {
            Value::VmFunction(ip, _) | Value::VmClosure(ip, _, _) => *ip,
            _ => return,
        };

        if self.chunk.fn_names.get(&ip).is_some_and(|existing| !existing.is_empty()) {
            return;
        }

        self.maybe_infer_function_name_from_key(ctx, key, key_value, val);
        let base = self.chunk.fn_names.get(&ip).cloned().unwrap_or_default();
        let accessor_name = format!("{} {}", prefix, base);
        self.chunk.fn_names.insert(ip, accessor_name.clone());

        if let Some(props) = self.fn_props.get(&ip).copied() {
            let should_update = {
                let borrow = props.borrow();
                match borrow.get("name") {
                    Some(Value::String(s)) => {
                        let current = crate::unicode::utf16_to_utf8(s);
                        current.is_empty() || current == base
                    }
                    Some(_) => false,
                    None => true,
                }
            };
            if should_update {
                let mut borrow = props.borrow_mut(ctx);
                borrow.insert("name".to_string(), Value::from(&accessor_name));
                borrow.insert("__readonly_name__".to_string(), Value::Boolean(true));
                borrow.insert("__nonenumerable_name__".to_string(), Value::Boolean(true));
            }
        }
    }

    fn invoke_getter_with_receiver(&mut self, ctx: &GcContext<'gc>, getter: &Value<'gc>, receiver: &Value<'gc>) -> Value<'gc> {
        match self.vm_call_function_value(ctx, getter, receiver, &[]) {
            Ok(v) => v,
            Err(err) => {
                self.set_pending_throw_from_error(&err);
                Value::Undefined
            }
        }
    }

    fn invoke_getter_with_receiver_mc(&mut self, ctx: &GcContext<'gc>, getter: &Value<'gc>, receiver: &Value<'gc>) -> Value<'gc> {
        let out = match getter {
            Value::VmFunction(ip, _) => {
                self.this_stack.push(receiver.clone());
                let saved = std::mem::take(&mut self.try_stack);
                let out = self.call_vm_function_result(ctx, *ip, &[], None, &[]);
                self.try_stack = saved;
                self.this_stack.pop();
                out
            }
            Value::VmClosure(ip, _, upv) => {
                self.this_stack.push(receiver.clone());
                let saved = std::mem::take(&mut self.try_stack);
                let uv = (**upv).to_vec();
                let out = self.call_vm_function_result(ctx, *ip, &[], None, &uv);
                self.try_stack = saved;
                self.this_stack.pop();
                out
            }
            Value::VmNativeFunction(id) => Ok(self.call_method_builtin(ctx, *id, receiver, &[])),
            Value::VmObject(obj) => {
                let borrow = obj.borrow();
                if let Some(Value::String(host_name_u16)) = borrow.get("__host_fn__") {
                    let host_name = crate::unicode::utf16_to_utf8(host_name_u16);
                    drop(borrow);
                    Ok(self.call_host_fn(ctx, &host_name, Some(receiver), &[]))
                } else {
                    Err(crate::raise_type_error!("Value is not a function"))
                }
            }
            _ => Err(crate::raise_type_error!("Value is not a function")),
        };

        match out {
            Ok(v) => v,
            Err(err) => {
                self.set_pending_throw_from_error(&err);
                Value::Undefined
            }
        }
    }

    fn read_named_property_with_receiver(
        &mut self,
        ctx: &GcContext<'gc>,
        obj: &Value<'gc>,
        key: &str,
        receiver: &Value<'gc>,
    ) -> Value<'gc> {
        if matches!(obj, Value::VmObject(map) if map.borrow().contains_key("__proxy_target__")) {
            match self.try_proxy_get(ctx, obj, key) {
                Ok(Some(value)) => return value,
                Ok(None) => {}
                Err(err) => {
                    self.set_pending_throw_from_error(&err);
                    return Value::Undefined;
                }
            }
        }

        let getter_key = format!("__get_{}", key);
        let mut current = Some(obj.clone());
        let mut depth = 0;
        while let Some(cur) = current {
            if depth > 100 {
                break;
            }
            depth += 1;

            match cur {
                Value::VmObject(map) => {
                    let borrow = map.borrow();
                    if key == "__proto__"
                        && let Some(val) = borrow.get(OWN_DUNDER_PROTO_DATA_KEY).cloned()
                    {
                        match val {
                            Value::Property { getter: Some(g), .. } => {
                                drop(borrow);
                                return self.invoke_getter_with_receiver(ctx, &g, receiver);
                            }
                            Value::Property { value: Some(v), .. } => {
                                return v.borrow().clone();
                            }
                            Value::Property { value: None, .. } => {
                                return Value::Undefined;
                            }
                            other => return other,
                        }
                    }
                    if key != "__proto__"
                        && let Some(val) = borrow.get(key).cloned()
                    {
                        if key == "prototype"
                            && (borrow.contains_key("__fn_body__")
                                || borrow.contains_key("__native_id__")
                                || borrow.contains_key("__bound_target__"))
                            && let Value::VmObject(proto_obj) = val.clone()
                        {
                            drop(borrow);
                            let needs_update = {
                                let proto_borrow = proto_obj.borrow();
                                !matches!(proto_borrow.get("constructor"), Some(existing) if self.values_same(existing, obj))
                            };
                            if needs_update {
                                let mut proto_borrow = proto_obj.borrow_mut(ctx);
                                proto_borrow.insert("constructor".to_string(), obj.clone());
                                proto_borrow.insert("__nonenumerable_constructor__".to_string(), Value::Boolean(true));
                            }
                            return Value::VmObject(proto_obj);
                        }
                        match val {
                            Value::Property { getter: Some(g), .. } => {
                                drop(borrow);
                                return self.invoke_getter_with_receiver(ctx, &g, receiver);
                            }
                            Value::Property { value: Some(v), .. } => {
                                return v.borrow().clone();
                            }
                            Value::Property { value: None, .. } => {
                                return Value::Undefined;
                            }
                            other => return other,
                        }
                    }
                    if let Some(getter_fn) = borrow.get(&getter_key).cloned() {
                        drop(borrow);
                        return self.invoke_getter_with_receiver(ctx, &getter_fn, receiver);
                    }
                    // Setter-only accessor: if __set_<key> exists but no getter/data, return undefined
                    let setter_key = format!("__set_{}", key);
                    if borrow.contains_key(&setter_key) {
                        return Value::Undefined;
                    }
                    if depth == 1 {
                        if let Some(Value::VmMap(map_data)) = borrow.get("__map_data__").cloned() {
                            match key {
                                "size" if !map_data.borrow().is_weak => return Value::Number(map_data.borrow().entries.len() as f64),
                                "set" => return Value::VmNativeFunction(BUILTIN_MAP_SET),
                                "get" => return Value::VmNativeFunction(BUILTIN_MAP_GET),
                                "has" => return Value::VmNativeFunction(BUILTIN_MAP_HAS),
                                "delete" => return Value::VmNativeFunction(BUILTIN_MAP_DELETE),
                                "keys" if !map_data.borrow().is_weak => return Value::VmNativeFunction(BUILTIN_MAP_KEYS),
                                "values" if !map_data.borrow().is_weak => return Value::VmNativeFunction(BUILTIN_MAP_VALUES),
                                "entries" if !map_data.borrow().is_weak => return Value::VmNativeFunction(BUILTIN_MAP_ENTRIES),
                                "forEach" if !map_data.borrow().is_weak => return Value::VmNativeFunction(BUILTIN_MAP_FOREACH),
                                "clear" if !map_data.borrow().is_weak => return Value::VmNativeFunction(BUILTIN_MAP_CLEAR),
                                _ => {}
                            }
                        }
                        if let Some(Value::VmSet(set_data)) = borrow.get("__set_data__").cloned() {
                            match key {
                                "size" if !set_data.borrow().is_weak => return Value::Number(set_data.borrow().values.len() as f64),
                                "add" => return Value::VmNativeFunction(BUILTIN_SET_ADD),
                                "has" => return Value::VmNativeFunction(BUILTIN_SET_HAS),
                                "delete" => return Value::VmNativeFunction(BUILTIN_SET_DELETE),
                                "keys" if !set_data.borrow().is_weak => return Value::VmNativeFunction(BUILTIN_SET_VALUES),
                                "values" if !set_data.borrow().is_weak => return Value::VmNativeFunction(BUILTIN_SET_VALUES),
                                "entries" if !set_data.borrow().is_weak => return Value::VmNativeFunction(BUILTIN_SET_ENTRIES),
                                "forEach" if !set_data.borrow().is_weak => return Value::VmNativeFunction(BUILTIN_SET_FOREACH),
                                "clear" if !set_data.borrow().is_weak => return Value::VmNativeFunction(BUILTIN_SET_CLEAR),
                                _ => {}
                            }
                        }
                    }
                    // Typed wrapper dispatch for String/Number/BigInt
                    if depth == 1 {
                        let type_name = borrow.get("__type__").map(|v| value_to_string(v));
                        match type_name.as_deref() {
                            Some("String") => {
                                let resolved = match key {
                                    "toString" | "valueOf" => Some(Value::VmNativeFunction(BUILTIN_STRING_VALUEOF)),
                                    "constructor" => {
                                        drop(borrow);
                                        return self.globals.get("String").cloned().unwrap_or(Value::Undefined);
                                    }
                                    "length" => {
                                        let len = match borrow.get("__value__") {
                                            Some(Value::String(sv)) => sv.len() as f64,
                                            _ => 0.0,
                                        };
                                        return Value::Number(len);
                                    }
                                    "split" => Some(Value::VmNativeFunction(BUILTIN_STRING_SPLIT)),
                                    "indexOf" => Some(Value::VmNativeFunction(BUILTIN_STRING_INDEXOF)),
                                    "slice" => Some(Value::VmNativeFunction(BUILTIN_STRING_SLICE)),
                                    "toUpperCase" => Some(Value::VmNativeFunction(BUILTIN_STRING_TOUPPERCASE)),
                                    "toLowerCase" => Some(Value::VmNativeFunction(BUILTIN_STRING_TOLOWERCASE)),
                                    "trim" => Some(Value::VmNativeFunction(BUILTIN_STRING_TRIM)),
                                    "charAt" => Some(Value::VmNativeFunction(BUILTIN_STRING_CHARAT)),
                                    "includes" => Some(Value::VmNativeFunction(BUILTIN_STRING_INCLUDES)),
                                    "replace" => Some(Value::VmNativeFunction(BUILTIN_STRING_REPLACE)),
                                    "replaceAll" => Some(Value::VmNativeFunction(BUILTIN_STRING_REPLACEALL)),
                                    "match" => Some(Value::VmNativeFunction(BUILTIN_STRING_MATCH)),
                                    "search" => Some(Value::VmNativeFunction(BUILTIN_STRING_SEARCH)),
                                    "startsWith" => Some(Value::VmNativeFunction(BUILTIN_STRING_STARTSWITH)),
                                    "endsWith" => Some(Value::VmNativeFunction(BUILTIN_STRING_ENDSWITH)),
                                    "substring" => Some(Value::VmNativeFunction(BUILTIN_STRING_SUBSTRING)),
                                    "padStart" => Some(Value::VmNativeFunction(BUILTIN_STRING_PADSTART)),
                                    "padEnd" => Some(Value::VmNativeFunction(BUILTIN_STRING_PADEND)),
                                    "repeat" => Some(Value::VmNativeFunction(BUILTIN_STRING_REPEAT)),
                                    "charCodeAt" => Some(Value::VmNativeFunction(BUILTIN_STRING_CHARCODEAT)),
                                    "trimStart" => Some(Value::VmNativeFunction(BUILTIN_STRING_TRIMSTART)),
                                    "trimEnd" => Some(Value::VmNativeFunction(BUILTIN_STRING_TRIMEND)),
                                    "lastIndexOf" => Some(Value::VmNativeFunction(BUILTIN_STRING_LASTINDEXOF)),
                                    _ => None,
                                };
                                if let Some(v) = resolved {
                                    return v;
                                }
                                if let Ok(idx) = key.parse::<usize>()
                                    && let Some(Value::String(str_val)) = borrow.get("__value__")
                                    && idx < str_val.len()
                                {
                                    let ch = String::from_utf16_lossy(&[str_val[idx]]);
                                    return Value::from(&ch);
                                }
                            }
                            Some("Number") => {
                                let resolved = match key {
                                    "toFixed" => Some(Value::VmNativeFunction(BUILTIN_NUM_TOFIXED)),
                                    "toExponential" => Some(Value::VmNativeFunction(BUILTIN_NUM_TOEXPONENTIAL)),
                                    "toPrecision" => Some(Value::VmNativeFunction(BUILTIN_NUM_TOPRECISION)),
                                    "toString" => Some(Value::VmNativeFunction(BUILTIN_NUM_TOSTRING)),
                                    "valueOf" => Some(Value::VmNativeFunction(BUILTIN_NUM_VALUEOF)),
                                    "constructor" => {
                                        drop(borrow);
                                        return self.globals.get("Number").cloned().unwrap_or(Value::Undefined);
                                    }
                                    _ => None,
                                };
                                if let Some(v) = resolved {
                                    return v;
                                }
                            }
                            Some("BigInt") => {
                                let resolved = match key {
                                    "toString" => Some(Value::VmNativeFunction(BUILTIN_NUM_TOSTRING)),
                                    "valueOf" => Some(Value::VmNativeFunction(BUILTIN_NUM_VALUEOF)),
                                    "constructor" => {
                                        drop(borrow);
                                        return self.globals.get("BigInt").cloned().unwrap_or(Value::Undefined);
                                    }
                                    _ => None,
                                };
                                if let Some(v) = resolved {
                                    return v;
                                }
                            }
                            _ => {}
                        }
                    }
                    let mut next = borrow.get("__proto__").cloned();
                    if next.is_none()
                        && let Some(Value::String(type_name_u16)) = borrow.get("__type__")
                    {
                        let type_name = crate::unicode::utf16_to_utf8(type_name_u16);
                        if let Some(Value::VmObject(ctor)) = self.globals.get(&type_name)
                            && let Some(proto) = ctor.borrow().get("prototype").cloned()
                        {
                            next = Some(proto);
                        }
                    }
                    // Some built-in singleton objects may not have __proto__ explicitly set;
                    // treat them as inheriting from Object.prototype for [[Get]] lookups.
                    if next.is_none()
                        && let Some(Value::VmObject(object_ctor)) = self.globals.get("Object")
                        && let Some(Value::VmObject(obj_proto)) = object_ctor.borrow().get("prototype")
                        && !Gc::ptr_eq(map, *obj_proto)
                    {
                        next = Some(Value::VmObject(*obj_proto));
                    }
                    current = next;
                }
                Value::VmFunction(ip, arity) => {
                    let current_fn = Value::VmFunction(ip, arity);
                    let props = self.get_fn_props(ctx, ip, arity);
                    let borrow = props.borrow();
                    // %ThrowTypeError% accessor on restricted function properties.
                    // Accessing inherited Function.prototype.arguments/caller should throw.
                    if (key == "caller" || key == "arguments")
                        && !borrow.contains_key(key)
                        && !borrow.contains_key(&getter_key)
                        && !borrow.contains_key(&format!("__set_{}", key))
                    {
                        let msg = "'caller', 'callee', and 'arguments' properties may not be accessed on strict mode functions or the arguments objects for calls to them";
                        drop(borrow);
                        self.throw_type_error(ctx, msg);
                        return Value::Undefined;
                    }
                    if let Some(val) = borrow.get(key).cloned() {
                        if key == "prototype"
                            && let Value::VmObject(proto_obj) = val.clone()
                        {
                            drop(borrow);
                            let needs_update = {
                                let proto_borrow = proto_obj.borrow();
                                !matches!(proto_borrow.get("constructor"), Some(existing) if self.values_same(existing, &current_fn))
                            };
                            if needs_update {
                                let mut proto_borrow = proto_obj.borrow_mut(ctx);
                                proto_borrow.insert("constructor".to_string(), current_fn.clone());
                                proto_borrow.insert("__nonenumerable_constructor__".to_string(), Value::Boolean(true));
                            }
                            return Value::VmObject(proto_obj);
                        }
                        return val;
                    }
                    if let Some(gf) = borrow.get(&getter_key).cloned() {
                        drop(borrow);
                        return self.invoke_getter_with_receiver(ctx, &gf, receiver);
                    }
                    current = borrow.get("__proto__").cloned();
                }
                Value::VmClosure(ip, arity, upvalues) => {
                    let current_fn = Value::VmClosure(ip, arity, upvalues);
                    let props = self.get_fn_props(ctx, ip, arity);
                    let borrow = props.borrow();
                    // %ThrowTypeError% accessor on restricted function properties.
                    // Accessing inherited Function.prototype.arguments/caller should throw.
                    if (key == "caller" || key == "arguments")
                        && !borrow.contains_key(key)
                        && !borrow.contains_key(&getter_key)
                        && !borrow.contains_key(&format!("__set_{}", key))
                    {
                        let msg = "'caller', 'callee', and 'arguments' properties may not be accessed on strict mode functions or the arguments objects for calls to them";
                        drop(borrow);
                        self.throw_type_error(ctx, msg);
                        return Value::Undefined;
                    }
                    if let Some(val) = borrow.get(key).cloned() {
                        if key == "prototype"
                            && let Value::VmObject(proto_obj) = val.clone()
                        {
                            drop(borrow);
                            let needs_update = {
                                let proto_borrow = proto_obj.borrow();
                                !matches!(proto_borrow.get("constructor"), Some(existing) if self.values_same(existing, &current_fn))
                            };
                            if needs_update {
                                let mut proto_borrow = proto_obj.borrow_mut(ctx);
                                proto_borrow.insert("constructor".to_string(), current_fn.clone());
                                proto_borrow.insert("__nonenumerable_constructor__".to_string(), Value::Boolean(true));
                            }
                            return Value::VmObject(proto_obj);
                        }
                        return val;
                    }
                    if let Some(gf) = borrow.get(&getter_key).cloned() {
                        drop(borrow);
                        return self.invoke_getter_with_receiver(ctx, &gf, receiver);
                    }
                    current = borrow.get("__proto__").cloned();
                }
                Value::VmArray(arr) => {
                    let borrow = arr.borrow();
                    let logical_len = self.vm_array_logical_length_u64(&borrow) as usize;
                    if key == "length" {
                        if let Some(Value::Number(n)) = borrow.props.get("__array_length__") {
                            return Value::Number(*n);
                        }
                        return Value::Number(borrow.elements.len() as f64);
                    }
                    if let Some(gf) = borrow.props.get(&getter_key).cloned() {
                        drop(borrow);
                        return self.invoke_getter_with_receiver(ctx, &gf, receiver);
                    }
                    if let Ok(idx) = key.parse::<usize>()
                        && idx < 0xFFFF_FFFF
                        && idx < logical_len
                        && idx < borrow.elements.len()
                        && !borrow.props.contains_key(&format!("__deleted_{}", idx))
                    {
                        return borrow.elements[idx].clone();
                    }
                    if let Some(val) = borrow.props.get(key).cloned()
                        && key
                            .parse::<usize>()
                            .map(|idx| idx >= 0xFFFF_FFFF || idx < logical_len)
                            .unwrap_or(true)
                    {
                        return val;
                    }
                    let setter_key = format!("__set_{}", key);
                    if borrow.props.contains_key(&setter_key) {
                        return Value::Undefined;
                    }
                    let mut next = borrow.props.get("__proto__").cloned();
                    if next.is_none()
                        && let Some(Value::VmObject(array_ctor)) = self.globals.get("Array")
                        && let Some(proto) = array_ctor.borrow().get("prototype").cloned()
                    {
                        next = Some(proto);
                    }
                    current = next;
                }
                _ => break,
            }
        }
        Value::Undefined
    }

    fn read_named_property(&mut self, ctx: &GcContext<'gc>, obj: &Value<'gc>, key: &str) -> Value<'gc> {
        match &obj {
            Value::VmObject(_) => self.read_named_property_with_receiver(ctx, obj, key, obj),
            Value::Object(obj_ref) => {
                if let Some(v) = crate::core::object_get_key_value(obj_ref, key) {
                    (*v.borrow()).clone()
                } else {
                    Value::Undefined
                }
            }
            Value::VmFunction(ip, arity) => {
                let current_fn = Value::VmFunction(*ip, *arity);
                let props = self.get_fn_props(ctx, *ip, *arity);
                let borrow = props.borrow();
                let value = borrow.get(key).cloned();
                let getter_key = format!("__get_{}", key);
                let getter_fn = borrow.get(&getter_key).cloned();
                let proto = borrow.get("__proto__").cloned();
                drop(borrow);
                if let Some(gf) = getter_fn {
                    return self.invoke_getter_with_receiver(ctx, &gf, obj);
                }
                if key == "prototype"
                    && let Some(Value::VmObject(proto_obj)) = value.clone()
                {
                    let needs_update = {
                        let proto_borrow = proto_obj.borrow();
                        !matches!(proto_borrow.get("constructor"), Some(existing) if self.values_same(existing, &current_fn))
                    };
                    if needs_update {
                        let mut proto_borrow = proto_obj.borrow_mut(ctx);
                        proto_borrow.insert("constructor".to_string(), current_fn.clone());
                        proto_borrow.insert("__nonenumerable_constructor__".to_string(), Value::Boolean(true));
                    }
                }
                value.or_else(|| self.lookup_proto_chain(proto.as_ref(), key)).unwrap_or(match key {
                    "call" => Value::VmNativeFunction(BUILTIN_FN_CALL),
                    "apply" => Value::VmNativeFunction(BUILTIN_FN_APPLY),
                    "bind" => Value::VmNativeFunction(BUILTIN_FN_BIND),
                    _ => Value::Undefined,
                })
            }
            Value::VmClosure(ip, arity, upvalues) => {
                let current_fn = Value::VmClosure(*ip, *arity, *upvalues);
                let props = self.get_fn_props(ctx, *ip, *arity);
                let borrow = props.borrow();
                let value = borrow.get(key).cloned();
                let getter_key = format!("__get_{}", key);
                let getter_fn = borrow.get(&getter_key).cloned();
                let proto = borrow.get("__proto__").cloned();
                drop(borrow);
                if let Some(gf) = getter_fn {
                    return self.invoke_getter_with_receiver(ctx, &gf, obj);
                }
                if key == "prototype"
                    && let Some(Value::VmObject(proto_obj)) = value.clone()
                {
                    let needs_update = {
                        let proto_borrow = proto_obj.borrow();
                        !matches!(proto_borrow.get("constructor"), Some(existing) if self.values_same(existing, &current_fn))
                    };
                    if needs_update {
                        let mut proto_borrow = proto_obj.borrow_mut(ctx);
                        proto_borrow.insert("constructor".to_string(), current_fn.clone());
                        proto_borrow.insert("__nonenumerable_constructor__".to_string(), Value::Boolean(true));
                    }
                }
                value.or_else(|| self.lookup_proto_chain(proto.as_ref(), key)).unwrap_or(match key {
                    "call" => Value::VmNativeFunction(BUILTIN_FN_CALL),
                    "apply" => Value::VmNativeFunction(BUILTIN_FN_APPLY),
                    "bind" => Value::VmNativeFunction(BUILTIN_FN_BIND),
                    _ => Value::Undefined,
                })
            }
            Value::VmNativeFunction(id) => {
                let props = self.get_native_fn_props(ctx, *id);
                let borrow = props.borrow();
                let value = borrow.get(key).cloned();
                let getter_key = format!("__get_{}", key);
                let getter_fn = borrow.get(&getter_key).cloned();
                let proto = borrow.get("__proto__").cloned();
                drop(borrow);
                if let Some(gf) = getter_fn {
                    return self.invoke_getter_with_receiver(ctx, &gf, obj);
                }
                value.or_else(|| self.lookup_proto_chain(proto.as_ref(), key)).unwrap_or(match key {
                    "call" => Value::VmNativeFunction(BUILTIN_FN_CALL),
                    "apply" => Value::VmNativeFunction(BUILTIN_FN_APPLY),
                    "bind" => Value::VmNativeFunction(BUILTIN_FN_BIND),
                    _ => Value::Undefined,
                })
            }
            Value::VmArray(arr) => {
                let borrow = arr.borrow();
                let logical_len = self.vm_array_logical_length_u64(&borrow) as usize;
                if key == "length" {
                    if let Some(Value::Number(n)) = borrow.props.get("__array_length__") {
                        return Value::Number(*n);
                    }
                    return Value::Number(borrow.elements.len() as f64);
                }
                // Check accessor properties
                let getter_key = format!("__get_{}", key);
                if let Some(gf) = borrow.props.get(&getter_key).cloned() {
                    drop(borrow);
                    return self.invoke_getter_with_receiver(ctx, &gf, obj);
                }
                if let Ok(idx) = key.parse::<usize>()
                    && idx < 0xFFFF_FFFF
                    && idx < logical_len
                    && idx < borrow.elements.len()
                    && !borrow.props.contains_key(&format!("__deleted_{}", idx))
                {
                    return borrow.elements[idx].clone();
                }
                if let Some(v) = borrow.props.get(key)
                    && key
                        .parse::<usize>()
                        .map(|idx| idx >= 0xFFFF_FFFF || idx < logical_len)
                        .unwrap_or(true)
                {
                    return v.clone();
                }
                let setter_key = format!("__set_{}", key);
                if borrow.props.contains_key(&setter_key) {
                    return Value::Undefined;
                }
                let mut proto = borrow.props.get("__proto__").cloned();
                if proto.is_none()
                    && let Some(Value::VmObject(array_ctor)) = self.globals.get("Array")
                    && let Some(array_proto) = array_ctor.borrow().get("prototype").cloned()
                {
                    proto = Some(array_proto);
                }
                drop(borrow);
                match proto {
                    Some(proto_value) => self.read_named_property_with_receiver(ctx, &proto_value, key, obj),
                    None => Value::Undefined,
                }
            }
            Value::VmMap(map) => match key {
                "size" => Value::Number(map.borrow().entries.len() as f64),
                "set" => Value::VmNativeFunction(BUILTIN_MAP_SET),
                "get" => Value::VmNativeFunction(BUILTIN_MAP_GET),
                "has" => Value::VmNativeFunction(BUILTIN_MAP_HAS),
                "delete" => Value::VmNativeFunction(BUILTIN_MAP_DELETE),
                "keys" => Value::VmNativeFunction(BUILTIN_MAP_KEYS),
                "values" => Value::VmNativeFunction(BUILTIN_MAP_VALUES),
                "entries" | "@@sym:1" => Value::VmNativeFunction(BUILTIN_MAP_ENTRIES),
                "forEach" => Value::VmNativeFunction(BUILTIN_MAP_FOREACH),
                "clear" => Value::VmNativeFunction(BUILTIN_MAP_CLEAR),
                "toString" => Value::VmNativeFunction(BUILTIN_OBJ_TOSTRING),
                _ => Value::Undefined,
            },
            Value::VmSet(set) => match key {
                "size" => Value::Number(set.borrow().values.len() as f64),
                "add" => Value::VmNativeFunction(BUILTIN_SET_ADD),
                "has" => Value::VmNativeFunction(BUILTIN_SET_HAS),
                "delete" => Value::VmNativeFunction(BUILTIN_SET_DELETE),
                "keys" | "values" | "@@sym:1" => Value::VmNativeFunction(BUILTIN_SET_VALUES),
                "entries" => Value::VmNativeFunction(BUILTIN_SET_ENTRIES),
                "forEach" => Value::VmNativeFunction(BUILTIN_SET_FOREACH),
                "clear" => Value::VmNativeFunction(BUILTIN_SET_CLEAR),
                "toString" => Value::VmNativeFunction(BUILTIN_OBJ_TOSTRING),
                _ => Value::Undefined,
            },
            _ => Value::Undefined,
        }
    }

    /// Merge an eval VM's chunk into the host VM's chunk so that VmFunction
    /// values produced by eval (getters, setters, methods) remain callable.
    /// Returns `(code_offset, const_offset)` used to adjust embedded IPs.
    fn merge_eval_chunk(&mut self, eval_chunk: &crate::core::opcode::Chunk<'gc>) -> (usize, usize) {
        let code_offset = self.chunk.code.len();
        let const_offset = self.chunk.constants.len();

        // Append eval constants, adjusting VmFunction IPs
        for c in &eval_chunk.constants {
            match c {
                Value::VmFunction(ip, arity) => {
                    self.chunk.constants.push(Value::VmFunction(ip + code_offset, *arity));
                }
                _ => {
                    self.chunk.constants.push(c.clone());
                }
            }
        }

        // Append eval code, adjusting constant indices and jump targets
        let ec = &eval_chunk.code;
        let mut pc = 0;
        while pc < ec.len() {
            let op_byte = ec[pc];
            self.chunk.code.push(op_byte);
            pc += 1;
            match crate::core::opcode::Opcode::try_from(op_byte) {
                // Opcodes with u16 constant index
                Ok(
                    crate::core::opcode::Opcode::Constant
                    | crate::core::opcode::Opcode::DefineGlobal
                    | crate::core::opcode::Opcode::DefineGlobalConst
                    | crate::core::opcode::Opcode::GetGlobal
                    | crate::core::opcode::Opcode::SetGlobal
                    | crate::core::opcode::Opcode::GetProperty
                    | crate::core::opcode::Opcode::SetProperty
                    | crate::core::opcode::Opcode::GetMethod
                    | crate::core::opcode::Opcode::NewError
                    | crate::core::opcode::Opcode::SetSuperProperty
                    | crate::core::opcode::Opcode::GetSuperProperty
                    | crate::core::opcode::Opcode::TypeOfGlobal
                    | crate::core::opcode::Opcode::DeleteGlobal
                    | crate::core::opcode::Opcode::DeleteProperty
                    | crate::core::opcode::Opcode::InitProperty,
                ) => {
                    if pc + 1 < ec.len() {
                        let idx = ec[pc] as u16 | ((ec[pc + 1] as u16) << 8);
                        let new_idx = idx + const_offset as u16;
                        self.chunk.code.push((new_idx & 0xff) as u8);
                        self.chunk.code.push(((new_idx >> 8) & 0xff) as u8);
                        pc += 2;
                    }
                }
                // Opcodes with u16 absolute jump target
                Ok(
                    crate::core::opcode::Opcode::Jump
                    | crate::core::opcode::Opcode::JumpIfFalse
                    | crate::core::opcode::Opcode::JumpIfTrue
                    | crate::core::opcode::Opcode::SetupTry,
                ) => {
                    if pc + 1 < ec.len() {
                        let target = ec[pc] as u16 | ((ec[pc + 1] as u16) << 8);
                        let new_target = target + code_offset as u16;
                        self.chunk.code.push((new_target & 0xff) as u8);
                        self.chunk.code.push(((new_target >> 8) & 0xff) as u8);
                        pc += 2;
                    }
                }
                // Call: 1 byte (possibly extended with u16)
                Ok(crate::core::opcode::Opcode::Call) => {
                    if pc < ec.len() {
                        let raw = ec[pc];
                        self.chunk.code.push(raw);
                        pc += 1;
                        if (raw & 0x3f) == 0x3f && pc + 1 < ec.len() {
                            self.chunk.code.push(ec[pc]);
                            self.chunk.code.push(ec[pc + 1]);
                            pc += 2;
                        }
                    }
                }
                // MakeClosure: u16 const_idx, u8 count, count * 2 bytes
                Ok(crate::core::opcode::Opcode::MakeClosure) => {
                    if pc + 2 < ec.len() {
                        let idx = ec[pc] as u16 | ((ec[pc + 1] as u16) << 8);
                        let new_idx = idx + const_offset as u16;
                        self.chunk.code.push((new_idx & 0xff) as u8);
                        self.chunk.code.push(((new_idx >> 8) & 0xff) as u8);
                        pc += 2;
                        let count = ec[pc] as usize;
                        self.chunk.code.push(ec[pc]);
                        pc += 1;
                        for _ in 0..count * 2 {
                            if pc < ec.len() {
                                self.chunk.code.push(ec[pc]);
                                pc += 1;
                            }
                        }
                    }
                }
                // 1-byte operand opcodes
                Ok(
                    crate::core::opcode::Opcode::GetLocal
                    | crate::core::opcode::Opcode::SetLocal
                    | crate::core::opcode::Opcode::NewArray
                    | crate::core::opcode::Opcode::NewObject
                    | crate::core::opcode::Opcode::GetUpvalue
                    | crate::core::opcode::Opcode::SetUpvalue
                    | crate::core::opcode::Opcode::CollectRest
                    | crate::core::opcode::Opcode::GetArguments
                    | crate::core::opcode::Opcode::NewCall,
                ) => {
                    if pc < ec.len() {
                        self.chunk.code.push(ec[pc]);
                        pc += 1;
                    }
                }
                // 0-operand opcodes (and unknown)
                _ => {}
            }
        }

        // Merge metadata with adjusted IPs
        for (ip, name) in &eval_chunk.fn_names {
            self.chunk.fn_names.insert(ip + code_offset, name.clone());
        }
        for (ip, len) in &eval_chunk.fn_lengths {
            self.chunk.fn_lengths.insert(ip + code_offset, *len);
        }
        for ip in &eval_chunk.class_constructor_ips {
            self.chunk.class_constructor_ips.insert(ip + code_offset);
        }
        for ip in &eval_chunk.derived_constructor_ips {
            self.chunk.derived_constructor_ips.insert(ip + code_offset);
        }
        for (ip, strict) in &eval_chunk.fn_strictness {
            self.chunk.fn_strictness.insert(ip + code_offset, *strict);
        }
        for ip in &eval_chunk.async_function_ips {
            self.chunk.async_function_ips.insert(ip + code_offset);
        }
        for ip in &eval_chunk.arrow_function_ips {
            self.chunk.arrow_function_ips.insert(ip + code_offset);
        }
        for (ip, names) in &eval_chunk.fn_local_names {
            self.chunk.fn_local_names.insert(ip + code_offset, names.clone());
        }
        for (ip, name) in &eval_chunk.call_callee_names {
            self.chunk.call_callee_names.insert(ip + code_offset, name.clone());
        }
        for ip in &eval_chunk.generator_function_ips {
            self.chunk.generator_function_ips.insert(ip + code_offset);
        }
        for ip in &eval_chunk.method_function_ips {
            self.chunk.method_function_ips.insert(ip + code_offset);
        }
        for &(ip, line, col) in &eval_chunk.line_map {
            self.chunk.line_map.push((ip + code_offset, line, col));
        }

        (code_offset, const_offset)
    }

    /// Recursively adjust VmFunction/VmClosure IPs in a value by adding `code_offset`.
    /// Only adjusts IPs that are in the provided set of eval function IPs.
    fn adjust_value_ips(
        &self,
        ctx: &GcContext<'gc>,
        val: &Value<'gc>,
        code_offset: usize,
        eval_fn_ips: &std::collections::HashSet<usize>,
    ) -> Value<'gc> {
        match val {
            Value::VmFunction(ip, arity) if eval_fn_ips.contains(ip) => Value::VmFunction(ip + code_offset, *arity),
            Value::VmClosure(ip, arity, upvals) if eval_fn_ips.contains(ip) => Value::VmClosure(ip + code_offset, *arity, *upvals),
            Value::VmObject(map) => {
                let mut needs_adjust = false;
                {
                    let borrow = map.borrow();
                    for (_, v) in borrow.iter() {
                        match v {
                            Value::VmFunction(ip, _) | Value::VmClosure(ip, _, _) if eval_fn_ips.contains(ip) => {
                                needs_adjust = true;
                                break;
                            }
                            _ => {}
                        }
                    }
                }
                if needs_adjust {
                    let mut borrow = map.borrow_mut(ctx);
                    let keys: Vec<String> = borrow.keys().cloned().collect();
                    for k in keys {
                        if let Some(v) = borrow.get(&k).cloned() {
                            let adjusted = self.adjust_value_ips(ctx, &v, code_offset, eval_fn_ips);
                            if !std::ptr::eq(&adjusted as *const _, &v as *const _) {
                                borrow.insert(k, adjusted);
                            }
                        }
                    }
                }
                val.clone()
            }
            Value::VmArray(arr) => {
                let mut needs_adjust = false;
                {
                    let borrow = arr.borrow();
                    for v in borrow.iter() {
                        match v {
                            Value::VmFunction(ip, _) | Value::VmClosure(ip, _, _) if eval_fn_ips.contains(ip) => {
                                needs_adjust = true;
                                break;
                            }
                            _ => {}
                        }
                    }
                }
                if needs_adjust {
                    let mut borrow = arr.borrow_mut(ctx);
                    for i in 0..borrow.len() {
                        let v = borrow[i].clone();
                        borrow[i] = self.adjust_value_ips(ctx, &v, code_offset, eval_fn_ips);
                    }
                }
                val.clone()
            }
            _ => val.clone(),
        }
    }

    fn ensure_super_base(&mut self, ctx: &GcContext<'gc>, receiver: &Value<'gc>) -> Result<Value<'gc>, JSError> {
        if let Some(super_base) = self.resolve_super_base(ctx, receiver) {
            return Ok(super_base);
        }

        let mut err_map = IndexMap::new();
        err_map.insert(
            "message".to_string(),
            Value::from("Cannot access 'super' of a class with null prototype"),
        );
        err_map.insert("__type__".to_string(), Value::from("TypeError"));
        let err = Value::VmObject(new_gc_cell_ptr(ctx, err_map));
        self.handle_throw(ctx, &err)?;
        Ok(Value::Undefined)
    }

    /// Walk the __proto__ chain looking for a property.
    fn lookup_proto_chain(&self, proto: Option<&Value<'gc>>, key: &str) -> Option<Value<'gc>> {
        let mut current = proto.cloned();
        let mut depth = 0;
        while let Some(ref p) = current {
            if depth > 100 {
                break;
            }
            depth += 1;
            match p {
                Value::VmObject(map) => {
                    let borrow = map.borrow();
                    if let Some(val) = borrow.get(key) {
                        return Some(val.clone());
                    }
                    let next = borrow.get("__proto__").cloned();
                    drop(borrow);
                    current = next;
                }
                Value::VmArray(arr) => {
                    let borrow = arr.borrow();
                    if key == "length" {
                        if let Some(Value::Number(n)) = borrow.props.get("__array_length__") {
                            return Some(Value::Number(*n));
                        }
                        return Some(Value::Number(borrow.elements.len() as f64));
                    }
                    if let Ok(idx) = key.parse::<usize>()
                        && idx < borrow.elements.len()
                        && !borrow.props.contains_key(&format!("__deleted_{}", idx))
                    {
                        return Some(borrow.elements[idx].clone());
                    }
                    if let Some(val) = borrow.props.get(key).cloned() {
                        return Some(val);
                    }
                    let mut next = borrow.props.get("__proto__").cloned();
                    if next.is_none()
                        && let Some(Value::VmObject(array_ctor)) = self.globals.get("Array")
                        && let Some(proto) = array_ctor.borrow().get("prototype").cloned()
                    {
                        next = Some(proto);
                    }
                    current = next;
                }
                Value::Null => break,
                _ => break,
            }
        }
        None
    }

